import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { getArtistes, deleteArtiste } from '../api/artisteService';

export default function ArtistesList() {
  const [artistes, setArtistes] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchArtistes = () => {
    setLoading(true);
    getArtistes()
      .then((response) => setArtistes(response.data || []))
      .catch(() => setArtistes([]))
      .finally(() => setLoading(false));
  };

  useEffect(() => {
    fetchArtistes();
  }, []);

  const handleDelete = (id) => {
    if (!window.confirm('Supprimer cet artiste ?')) return;
    deleteArtiste(id).then(() => fetchArtistes());
  };

  return (
    <div>
      <div className="d-flex align-items-center justify-content-between mb-4">
        <div>
          <h1 className="h3 mb-0">Artistes</h1>
          <p className="text-muted mb-0">Liste des artistes avec leurs descriptions et images.</p>
        </div>
        <Link className="btn btn-primary" to="/artistes/create">
          Créer un artiste
        </Link>
      </div>

      {loading ? (
        <div className="alert alert-secondary">Chargement des artistes...</div>
      ) : artistes.length === 0 ? (
        <div className="alert alert-warning">Aucun artiste trouvé.</div>
      ) : (
        <div className="table-responsive">
          <table className="table table-hover align-middle">
            <thead className="table-light">
              <tr>
                <th>Artiste</th>
                <th>Description</th>
                <th>Image</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {artistes.map((artiste) => (
                <tr key={artiste.id}>
                  <td>
                    <Link to={`/artistes/${artiste.id}`} className="fw-bold">
                      {artiste.nom || `Artiste ${artiste.id}`}
                    </Link>
                    <div className="text-muted small">ID: {artiste.id}</div>
                  </td>
                  <td>{artiste.description || 'Aucune description'}</td>
                  <td>
                    {artiste.image ? (
                      <img
                        src={`/uploads/images/${artiste.image}`}
                        alt={artiste.nom}
                        className="img-thumbnail"
                        style={{ maxWidth: 80, maxHeight: 80 }}
                      />
                    ) : (
                      <span className="text-muted">Aucune image</span>
                    )}
                  </td>
                  <td>
                    <Link className="btn btn-sm btn-outline-secondary me-2" to={`/artistes/${artiste.id}/edit`}>
                      Modifier
                    </Link>
                    <button className="btn btn-sm btn-danger" onClick={() => handleDelete(artiste.id)}>
                      Supprimer
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
